refsection.programlisting:
image = imread(fullpath(getIPCVpath() + "/images/opencv_smarties.png"));
image = imresize(rgb2gray(image), [120 160]);
mask = imroi2mask([30 30 100 60], [size(image, 1) size(image, 2)], "rectangle");
distance = imbwdistgeodesic(mask, [80 60], 8);
subplot(1, 2, 1);
imshow(mask);
subplot(1, 2, 2);
imshow(distance, hot(64));
